import{_ as p,o as e,c as a,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"奇特的故事","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/奇特的故事.md","filePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/奇特的故事.md"}'),s={name:"4.资源分区/7.物品与装备/4.奇物/6.可升级/奇特的故事.md"};function o(d,b,i,l,_,c){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"奇特的故事",tabindex:"-1"},[t("奇特的故事 "),r("a",{class:"header-anchor",href:"#奇特的故事","aria-label":'Permalink to "奇特的故事"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),n('<h1 id="奇特的故事-1" tabindex="-1">奇特的故事 <a class="header-anchor" href="#奇特的故事-1" aria-label="Permalink to &quot;奇特的故事&quot;">​</a></h1><p>奇特的故事<br> 特异本质<br> 注：<br> 该资源所有下属可任意购买，若无特殊说明，无需前置。<br> 该资源下属所有面具均使用差价升级，若无特殊说明，效果叠加生效。<br> 红死钦差系列武器均使用差价升级，若无特殊说明，效果替换生效。</p><p>“哦，快坐下我的孩子，我接下来要讲述一个从未有人讲述过的故事”</p><p>序章：故事的开始</p><p>“故事的开始，很久很久以前，一个小丑来到了一座城里。<br> 我们应该将目光聚焦在小丑身上，但是抱歉，我不得不抽空去讲述这座城市，<br> 那是一座怎样的城市啊！世界上一切美好，一切的梦都在哪里，尤其尤其是国王的宫殿，<br> 就如同被上天眷恋，国王的宫殿被一整块天空笼罩，除了国王和他所准许的，那些高贵的人们，无人可以进入，<br> 天空是由整块整块的青金石雕刻而成的，而在天空上面，太阳是永远熔融的黄铜，在它对面的是永远透着亮光的大理石月亮，<br> 那些星星，那些无与伦比的星星，每一颗都是比现在最大的钻石还要大的钻石。”</p><p>小丑的面具<br> D+500<br> 占据面具位</p><p>“而就在这座不可思议的城市里面，来了这么一位不可思议的小丑，<br> 无论什么样的话语，从他嘴里吐出都会变成甜言蜜语，<br> 无论什么样的把戏，在他手下都会变得如同魔鬼到来一样神奇！<br> 整座整座城市的人都围在他身边，他们时而笑的前仰后合，时而为小丑的危险表演提心吊胆，这是怎么样的小丑啊！<br> 只有在这时，所有所有的人们才能忘却自己眼前的饥渴，绝望，和撕心裂肺的病痛，迫在眉睫的死亡。”</p><p>这是一副木制面具，面具的模样为一名小丑，小丑的笑容夸张而滑稽，<br> 但是在面具的正面有着些许暗红色接近黑色的污渍，尚且不知晓其构成，<br> 佩戴它，则视作你自愿加入一场伟大的歌剧之中，<br> 你会获得黑暗视觉和灵感视觉，因为只有这样，你才能看到舞台角落，那隐藏于黑暗中的的国王，<br> 仅一次，若你在一场影片中经过一次同级战斗并且获胜，你可以在战斗后进行一次祭献，具体动作为将鲜血涂抹于面具上，<br> 若如此做，则在那次影片结束后，你在使用红死钦差系列武器时，额外使豁免的DC上升2点，能造成的最大毒素异常点数则增加2点。</p><p>红死钦差·愚人杖<br> D+500<br> 【这是一把长度约为120厘米，款式接近伊比利亚直剑的长剑，<br> 其剑身大部分被暗红色绷带捆束，从部分未被缠绕的位置可以看见其剑身，其剑身高度腐朽，按照常理已经失去了挥砍的能力，但是经测试，这把长剑仍然能起到削铁如泥的效果，<br> 试图解开其绷带的实验宣告失败，绷带的材质无法辨认，其在剑柄处有着一个以未知原理悬浮的金属圆环，圆环大部分镀金，但是其余未镀金部分则严重腐朽，<br> 圆环上刻有铭文，经测试，其上的铭文会跟随持有者当前是否佩戴面具，佩戴面具种类切换，并且圆环的形制也会发生变化，<br> 以下为已记录的类型：<br> 未佩戴面具：铭文固定为“Portentosa Fabula”，意为“光怪陆离的故事”。<br> 佩戴小丑的面具：圆环转变为斯拉修裂口的外观，其上的铭文变为“Sub umbra desperationis ”，意为“伏于阴影”。】</p><p>武器伤害：6L，武器类型：剑，武器体积：3，</p><p>这把武器具有【法破】效果，且使用这把剑会减少1点意志力上限，<br> 当该武器击中敌人时，敌人需进行一次DC为9的强韧豁免，若失败则承受差值点毒素异常点数（最多1点），这是一个武器等级的疾病来源的效果。<br> 特殊的，若你此时佩戴了小丑的面具，且已经进行过其中的祭献行动，那么DC额外上升1点。</p><p>第一幕：愚人的故事<br> “我们说到哪了？哦对，那个神奇的小丑，他吸引了全城的人，自然也吸引了独居的一个愚人，<br> 那个愚人啊，他是如此的愚蠢笨拙，以至于被全城的人都讨厌，他们躲避他，躲避他身上的死亡气味，他是住在坟地里面的，<br> 那天，愚人在收捡全部的尸体之后，听见了人们的笑声，那笑声的主人笑的是如此畅快，以至于愚人不由得担心他们会把自己的肺笑破，<br> 但是愚人也在想，啊，那是怎么样的有趣，怎么样的精彩呢，于是愚人放下了尸体，赶往了小丑身边。”</p><p>愚人的面具<br> C+1000<br> 占据面具位</p><p>“愚人被自己的好奇心战胜了，他就是这样没有自制力，所以人们才会避开他，<br> 而当他看见那个小丑光怪陆离的把戏，奇特的舞蹈，滑稽的笑声，以及那一个个让人愈发沉醉的笑话时，<br> 他忍不住的喝彩，而这让周围的人发现了他，所有人的目光停留在了他身上一瞬，这让他几乎要逃跑了，<br> 但是谁又能忍住不去看这个小丑呢？所有人都是这么想的，于是他们虽然避开了愚人，但是仍然围着小丑，一下子，愚人的周围便变成了一片空地”</p><p>这是一幅部分镀银的木制面具，面具的形象为上半面容被刻意抹去，边缘为斗篷的人形，<br> 面具的内部，口部对应位置有一些暗红色污渍，<br> 佩戴它，意味着你已经正式完成了排练，接下来即将正式表演，<br> 在使用红死钦差系列武器时，你可以同时击中触及范围内的全部敌人，<br> 当你使用的红死钦差系列武器等级达到C时，使其DC增加1点，最大能施加的毒素异常点数则增加1点。</p><p>红死钦差·守夜人提灯<br> C+1000<br> “愚人被众人排斥，他本人对此已经习以为常，但是小丑怎么可能看见有人被孤立呢，那可是最难以置信的小丑啊，<br> 于是小丑抓住了愚人的肩膀，将愚人变成了自己表演的一环，于是人们再次爆发出阵阵笑声，于是人们再次欢呼，于是人们再次忘却，<br> 当表演结束，愚人第一次发现自己可以站到众人中间了。<br> ‘啊，这是怎样一个神奇的小丑啊’，他这么想着，就在这时，他突然想到，应该让国王看见，那可是这个国家最尊贵最伟大的人，他一定会喜欢这个小丑，<br> ‘但是我既不高贵，也没有才华，我该怎么进入国王的宫殿呢？’，他在大街上发问，于是人群指给了他一条道路，‘哪里住着知识最渊博的贤者，你去找他吧’，人们这么说道，<br> 于是愚人去寻找贤者。”</p><p>【佩戴愚人的面具，金属圆环变形为仅覆盖小臂的臂甲，其上的铭文变化为：“Periculum Mortis Imminens”，意为“死亡之隐”】</p><p>武器伤害：11L，武器类型：剑，武器体积：3，</p><p>这把武器具有【法破】【9加骰】效果，且使用这把剑会减少2点意志力上限，<br> 当该武器击中敌人时，敌人需进行一次DC为17的强韧豁免，若失败则承受差值点毒素异常点数（最多1点），这是一个武器等级的疾病来源的效果。<br> 特殊的，若你此时佩戴了小丑的面具或其升级，且已经进行过其中的祭献行动，那么DC额外上升1点。</p><p>第二章：贤者的故事</p><p>“愚人走啊走，他在道路尽头看见了一座最高最高的高塔，只有国王的宫殿才比这座塔高，而贤者就住在塔顶，<br> 可怜的小小愚人啊，他没办法爬上高塔，因为贤者有着最忠诚的守卫，看守着高塔的大门，<br> 愚人只能请求守卫传达，守卫讪笑着赶走了他，可不要误会，这是因为贤者所见的人会且只会是这个国家最尊贵的那一批人，可不能让愚人的思维污染了贤者的聪明才智”</p><p>贤者的面具<br> B+2000</p><p>“在饮酒，欢乐，吟诗，与无休止的宴会后，就在天空开始变红的时候，贤者终于从他那繁琐的事务中脱身，<br> 于是他的守卫立刻上报，他的守卫说：‘我们发现城里有一个最厉害的小丑，他能把死人说活，您一定要去看看’，<br> 贤者于是吩咐守卫将小丑带到他的高塔之中”<br> “那些最忠诚的守卫把小丑从人们之中带走，人们可是那么的不愿意离开小丑啊！于是他们远远的跟着，<br> 直到忠诚的守卫用枪刺穿了其中一人，人们才一哄而散，‘这都是为了贤者和国王’，那些忠诚的守卫这么说着，于是小丑被带到了贤者面前”</p><p>这是一幅银面具，面具的形态为一名肥胖的贵族，<br> 在面具的额头与脸颊部分分布大量暗红色血迹，<br> 佩戴者在使用红死钦差系列武器时，攻击检定上的加骰额外上升一级（最高8加骰），<br> 此外，佩戴者在使用红死钦差系列武器时，额外使豁免的DC上升4点，能造成的最大毒素异常点数则增加3点。</p><p>红死钦差·贤者权杖<br> B+2000<br> “贤者终于见到了那个最厉害的小丑，‘你能做什么？’贤者这样问了，于是小丑这样答道‘我能为你带来你所希望的’，<br> 就像我说的，这是一个神奇的小丑，所以他轻而易举的就得到了贤者的欢心，贤者要求小丑为他表演了一天又一天，<br> 就在这时，伟大的国王传令贤者，邀请贤者去往国王的宫殿参加一场盛大的舞会，<br> ‘我一定要让国王看见这个小丑’，贤者这么想到，于是他让他最忠诚的士兵看守小丑，与小丑一同前往国王的宫殿。”</p><p>【佩戴贤者的面具，金属圆环变形为手镯，其上铭文变化为：“Species Pulchra”，意为“虚假之美”】</p><p>武器伤害：18L，武器类型：剑，武器体积：3，</p><p>这把武器具有【法破】【9加骰】效果，且使用这把剑会减少2点意志力上限，在使用这把武器攻击时，<br> 当该武器击中敌人时，敌人需进行一次DC为27的强韧豁免，若失败则承受差值点毒素异常点数（最多3点），这是一个武器等级的疾病来源的效果。<br> 特殊的，若你此时佩戴了小丑的面具或其升级，且已经进行过其中的祭献行动，那么DC额外上升1点。<br> 在一场影片后，一轮一次，你可以在攻击结束后令对方身上的毒素异常点数立刻生效一次，这是一个激爆效果。</p><p>第三幕：国王的故事</p><p>“国王的宫殿是一个宏伟的建筑，除了上述种种，其中更是有着国王那令人敬畏却又吸引着众人的情趣与风骨，<br> 而最令这个宫殿不同于其他建筑的，就是国王在里面安排了所有享乐与美好，是的，在那里面有着供人逗乐的小丑，吟诵诗句的诗人，悦动不止的舞女，<br> 美食和美酒更是取之不尽，于是国王便可以在宫殿内每日每日的放声纵乐，于是宫殿内只余欢乐，仔细算来，这座宫殿已经建成了6个月了，<br> 而就在这值得纪念的日子，国王邀请贤者，还有诸多欢乐的人们，来参加他的舞会。”</p><p>国王的面具<br> A+4000<br> “舞会的会场骄奢异常，国王的品味更是难以捉摸，他将自己的宫殿划分为了7个区域，最东边的那间有着蓝色的挂饰，于是地板和窗户也是蓝色的，<br> 第二间则是紫色的，第三件房里花草盎然，便是绿色的，第四间的家具均为黄色，于是从窗户透进来的光也是黄的，第五间是白色，第六间房则是紫罗兰色，<br> 而最后一间，黑丝绒覆盖了整个房间，而且只有最后一个房间的窗户与其内饰不同，最后一个房间的窗户是鲜红的，光线透过窗户打在地板上，如同一抹鲜血。”<br> “国王的喜好即深邃又古怪，有些人认为他多少是有些疯狂的，在他的一手操办下，一场别开生面的化妆舞会开始了，有些人打扮的荒唐，有些人打扮的漂亮，<br> 那些平时看不见的色彩，现在都充斥在这6个房间中，他们如同梦一样，在房间内扭进扭出，嘈杂的舞步伴随着乐队的演奏，一颗颗快活的心脏泵着鲜红的鲜血。<br> 但是没人敢踏入第7个房间，那里太阴暗，太恐怖了，而每3600秒，在第7个房间内的巨钟就会鸣响，那声音即威严又恐怖，于是所有人都停下来，等到钟响结束。”<br> “在第5次钟响之后又过了四分之三个钟响的时间后，贤者对国王说：‘我请到了一个最厉害的小丑，他一定能为您的舞会增添色彩’，于是国王下令带他上来。<br> 但是忠诚的士兵一去不返，狂欢的人们也不会在意，就这样到了下一次钟响的时间。”<br> “而第6次钟响时，那威严又恐怖的声音再次传遍所有的房间，人们不得不停下狂欢，智者或年长者开始沉思，年轻者或轻浮者则面色惨白，<br> 他们祈祷着这钟声能快些过去，但是这次钟需要响足12下，所以人们只能继续沉思，继续惊恐，<br> 所以他们才能发现一位不速之客在不知道什么时候，已经混进了会场之中。”</p><p>【附录：于后续的发掘中，我们在地下约5公里处发现了一处废墟，其被推测为因为地质活动而被掩埋，然而未能找到引发该现象的地质活动的记录。<br> 废墟据测量，原为一座占地约600平方公里的城市，其中的建筑物保存良好，推测距今约■■■年，<br> 其中有着一种现代科学无法解释的影响，该影响直接导致废墟内的所有物品被保存在了某个时间点，就连食物也被测定为依旧可以食用，<br> 但是其中并没有任何人类痕迹，包括骸骨等，对该地区的探索正在展开。】<br> 【在推测为国王宫殿中的王座上，我们发现了一幅与之前发现的面具推测为同时铸造的面具，其被命名为‘国王的面具’，并且在其之下我们发现了一条便签，翻译后文本记录如下：<br>  ‘红死 ’ 在国内肆虐很久了。如此致命而骇人的瘟疫可谓前所未有。<br> 这种病的具体表现和鲜明特征就是出血——红色漫卷，令人齿寒。剧痛袭来不久，是突如其来的头晕眼花，接着毛孔血流不止，人于是必死无疑。<br> 一旦猩红色的斑点在谁的身上——尤其是在脸上出现，这人就给戳上了红死病的标签，即便是亲朋好友也不敢靠近。<br> 这人就陷入孤绝之境，没人援助，没人同情。从染病、发病到送命，不过短短半小时罢了。】</p><p>这是一幅纯金面具，但是其几乎完全被暗红色血污附盖，且无法擦去，<br> 面具的形象为一个戴着王冠的国王，其双眼被红铜封死，<br> 受诅咒者不被赐福，不受伤苦，免疫A级祝福来源和A级创伤来源的效果，<br> 此外，在使用红死钦差系列武器时，额外使豁免的DC上升4点，能造成的最大毒素异常点数则增加3点。</p><p>红死钦差<br> A+4000<br> “那人披着一幅裹尸布，脸上戴着足以以假乱真的死者面具，这即无情趣，也不合礼仪，尽管国王为了舞会的欢乐，几乎没有规范可言，但是这个陌生人的装扮显然已经超过了界限，<br> 如果仅仅如此，那么寻欢作乐的人们还能容忍，但是陌生人太大胆，居然在裹尸布上泼满鲜血，在面具上覆上红死病的象征，那恐怖的妆造令人战栗不已。”<br> “国王震怒了，他大声呼唤着人们去拿下这个不知天高地厚的家伙，事实上，当他刚下令时，还有一些人朝着陌生人走了一步，但是谁曾想那陌生人毫无畏惧，<br> 他径直朝着国王走了过去，那傲慢而从容的步伐，让人们产生了一种畏惧，于是那个陌生人就这么从国王身边走了过去，依次经过蓝色房间，紫色房间，然后是绿色，黄色，白色，紫罗兰色，<br> 而这时，恼怒的国王拔出了自己的短剑，朝着那个陌生人冲过去，他们几乎是同时踏入黑色房间的，但是房间内依旧静悄悄的”<br> “狂欢的人们花了好久在重新捡起来自己的信心，他们这才一拥而上挤进最后一个房间，而在他们面前的，已经不见了国王，只有那个陌生人和掉在地上的短剑，<br> 于是人们开始愤怒，他们捡起地上的短剑刺向陌生人，或者说，他们用能找到的一切刺向陌生人，烛台，烟杆，指甲，牙齿……<br> 而在这混乱中，贤者突然惊呼出声‘哦，我的王！’人们顺着他的手指指的方向看去，发现贤者指着的正是陌生人，在短暂的寂静后，胆子最大的那人掀开了陌生人的裹尸布，取下了那死者的面具，<br> 而藏匿在裹尸布下的无理之徒，正是国王本人，现在他的心脏被他自己的短剑刺穿，他的身体被撕扯成了布块”<br> “钟声不紧不慢的响着，人们抬头看向其他人，所有人都戴着足矣以假乱真的死者面具，所有人都穿着裹尸布，于是人们开始互相撕扯，互相感染，被撕扯者转变为撕扯者，被感染者转化为感染者，<br> 最后，在不多不少的第12声钟响结束的时候，所有人都已经沉寂下去，红死病在悄无声息间溜了进来，带走了所有的生命。”</p><p>【在佩戴国王的面具之后，剑的整体形制首次发生了改变，暴露在外的腐朽部位转变为了形似生物尖牙的不规则形态，金属圆环转变为一幅手铐，其上的铭文变更为：‘Fata non effugienda sunt’，意为“宿命难违”】</p><p>武器伤害：32L，武器类型：剑，武器体积：3，</p><p>这把武器具有【法破】【9加骰】效果，且使用这把剑会减少2点意志力上限，在使用这把武器攻击时，<br> 当该武器击中敌人时，敌人需进行一次DC为47的强韧豁免，若失败则承受差值点毒素异常点数（最多9点），这是一个武器等级的疾病来源的效果。<br> 特殊的，若你此时佩戴了小丑的面具或其升级，且已经进行过其中的祭献行动，那么DC额外上升1点。<br> 在一场影片后，一轮一次，你可以在攻击结束后令对方身上的毒素异常点数立刻生效一次，这是一个激爆效果。<br> 当你使用这把武器进行攻击时，可以将伤害出目转为等量的毒素异常点数，<br> 一轮一次，以该武器发动的攻击的出目增加一半，<br> 若你此时佩戴有国王的面具，那么转为附带伤害出目点的毒素异常点数。</p><p>第四幕：寂静<br> “就这样，红死病派遣装扮成小丑的腐朽，攻下了城市，随后开始了对一切漫漫无期的统治”</p><p>苍白的面具<br> S+8000<br> 该物品默认不可购买，需要ST选开才可以购买。</p><p>昔有亲王，深宫宴饮<br> 红死在外，高墙自固<br> 管弦声起，七室生辉<br> 翩翩起舞，无视死寂</p><p>彩窗迷离<br> 烛台倾倒<br> 钟声回荡<br> 面具欢愉</p><p>锦缎裹身，珠宝环绕<br> 亲王骄奢，死神不见<br> 小丑讪笑，宾客迷醉<br> 黑钟轰鸣，倏然静默<br> 猩红身影，立于西厅<br> 昔日欢颜，惊惶退避<br> 丝绒污损，假面脱落<br> 红露沾染，气息终亡</p><p>徘徊之病，无孔不入<br> 黑暗殿堂，听其所祷<br> 生命已逝，狂欢骤止<br> 其容惨怖，其迹如疫<br> 埋葬之时，红死未逝<br> 逃离之时，红死已生<br> 君临七室，重掌权柄<br> 恐惧绝望，随之而至</p><p>如是红死，不治生者<br> 如是生者，皆归其辖<br> 古堡沦丧，死寂浮现<br> 猩红之影，游荡其间<br> 红病端坐，王座之上<br> 华服尸骸，服侍如前<br> 假面永覆，苦痛永存<br> 钟声不止，众生永望</p><p>这是一幅材质不明的苍白的死者面具，其上刻画的人物为一具白骨，<br> 所有看见佩戴者的人都需要以强韧豁免进行一次豁免，DC为48，若失败，则感染【红死病】，其会在30分钟内死亡，这是一个S级疾病来源的模因和即死效果，<br> 特殊的，若你使用红死钦差系列武器，那么你也可以改为使用其中的DC作为强韧豁免的难度。<br> 所有看见因【红死病】死亡的尸体的人也需要进行这次强韧豁免，该模因的传播范围最大为一个国家。</p><p>红死钦差<br> S+8000<br> 该武器默认不可购买，需要ST选开才可以购买。</p><p>钟声骤止<br> 赤帷低垂<br> 所谓红死<br> 幽幽徘徊</p><p>殿有七色<br> 窗映诡光<br> 假面幽冥<br> 旋舞癫狂</p><p>锦缎翻飞<br> 琴弦断裂<br> 若见猩袍<br> 乐乎哀哉</p><p>回廊曲折<br> 若冥若幻<br> 彩玻璃碎<br> 去不复返</p><p>诸侯贵胄<br> 惊其华艳<br> 死神黑袍<br> 立彼殿前</p><p>众生之息<br> 红死饮之<br> 亲王之血<br> 尽染阶前</p><p>钟声寂然<br> 赤帷黯黯<br> 所谓红死<br> 永驻殿台</p><p>如是假面犹舞不止</p><p>武器伤害：56L，武器类型：剑，武器体积：3，</p><p>这把武器具有【法破】【9加骰】效果，且使用这把剑会减少2点意志力上限，在使用这把武器攻击时，<br> 当该武器击中敌人时，敌人需进行一次DC为51的强韧豁免，若失败则承受差值点毒素异常点数（最多3点），这是一个武器等级的疾病来源的效果。<br> 特殊的，若你此时佩戴了小丑的面具或其升级，且已经进行过其中的祭献行动，那么DC额外上升1点。<br> 一轮一次，你可以在攻击结束后令对方身上的毒素异常点数立刻生效一次，这是一个激爆效果。<br> 当你使用这把武器进行攻击时，可以附带伤害出目点的毒素异常点数，<br> 一轮一次，以该武器发动的攻击的出目增加一半，且具有【传奇】特性。<br> 当攻击命中时，敌人需以强韧豁免伤害出目，若失败，则感染【红死病】并立刻病发身亡，这是一个S级疾病来源的即死效果，<br> 无论如何，以该武器造成的毒素异常点数均视作第四档异常点数。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',58)])])}const h=p(s,[["render",o]]);export{D as __pageData,h as default};
